t.t:
.page-hero { background: linear-gradient(135deg, var(--primary) 0%, #185FA5 100%); border-radius: 12px; padding: 36px 40px; margin-bottom: 28px; color: #fff; position: relative; overflow: hidden; }
.page-hero::after { content: ''; position: absolute; right: -40px; top: -40px; width: 220px; height: 220px; border-radius: 50%; background: rgba(255,255,255,0.05); }
.page-hero h1 { font-family: 'Source Serif 4', serif; font-size: 26px; font-weight: 600; margin-bottom: 8px; position: relative; }
.page-hero p { font-size: 14px; color: rgba(255,255,255,0.75); max-width: 500px; }
.filter-bar { display: flex; align-items: center; gap: 10px; margin-bottom: 24px; flex-wrap: wrap; }
.search-wrap { position: relative; flex: 1; min-width: 200px; max-width: 340px; }
.search-wrap input { width: 100%; padding: 8px 12px 8px 36px; border: 1px solid var(--border); border-radius: 6px; font-size: 13px; font-family: inherit; background: var(--bg-card); color: var(--text-primary); outline: none; transition: border 0.15s; }
.search-wrap input:focus { border-color: var(--primary); }
.search-icon { position: absolute; left: 11px; top: 50%; transform: translateY(-50%); color: var(--text-muted); font-size: 13px; }
.filter-pills { display: flex; gap: 6px; flex-wrap: wrap; }
.filter-pill { padding: 5px 14px; border-radius: 20px; font-size: 12.5px; border: 1px solid var(--border); background: var(--bg-card); color: var(--text-muted); cursor: pointer; transition: all 0.15s; font-family: inherit; }
.filter-pill.active, .filter-pill:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.cards-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 18px; }
.opp-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 20px; display: flex; flex-direction: column; gap: 12px; transition: box-shadow 0.2s, transform 0.2s; cursor: pointer; text-decoration: none; }
.opp-card:hover { box-shadow: 0 4px 16px rgba(15,76,129,0.10); transform: translateY(-2px); }
.opp-card-top { display: flex; align-items: flex-start; justify-content: space-between; }
.company-row { display: flex; align-items: center; gap: 8px; margin-top: 4px; }
.company-dot { width: 28px; height: 28px; border-radius: 50%; background: var(--primary-light); color: var(--primary); font-size: 10px; font-weight: 700; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.company-name { font-size: 12px; color: var(--text-muted); }
.opp-title { font-size: 14.5px; font-weight: 600; color: var(--text-primary); line-height: 1.4; }
.opp-desc { font-size: 13px; color: var(--text-muted); line-height: 1.5; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
.opp-footer { display: flex; align-items: center; justify-content: space-between; margin-top: auto; padding-top: 8px; border-top: 1px solid var(--border); }
.deadline { font-size: 11.5px; color: var(--text-muted); }
.deadline strong { color: var(--text-primary); }

t.script:
let activeFilter = 'todos';
function setFilter(el, tipo) { 
    document.querySelectorAll('.filter-pill').forEach(p => p.classList.remove('active')); 
    el.classList.add('active'); 
    activeFilter = tipo; 
    filterCards(); 
}
function filterCards() { 
    const q = document.getElementById('opp-search').value.toLowerCase(); 
    document.querySelectorAll('.opp-card').forEach(card => { 
        const matchTipo = activeFilter === 'todos' || card.dataset.tipo === activeFilter; 
        const matchQ = !q || card.dataset.search.toLowerCase().includes(q); 
        card.style.display = (matchTipo && matchQ) ? '' : 'none'; 
    }); 
}
